designs.rtl:
module buf1_leaf (
    input logic a,
    output logic y
);
    assign y = a;
endmodule

designs.tb_text:
module buf1_leaf_tb;
  logic a;
  logic y;

  buf1_leaf dut (
    .a(a),
    .y(y)
  );

  initial begin
    a = 1'b0;
    #1;
    if (y !== 1'b0) $fatal(1, "buf1_leaf failed for a=0");
    a = 1'b1;
    #1;
    if (y !== 1'b1) $fatal(1, "buf1_leaf failed for a=1");
    $display("PASS");
    $finish;
  end
endmodule
